import{c as e,Q as a,j as n,m as t}from"./chunks/framework.D9IbVcwA.js";const u=JSON.parse('{"title":"020-proc-scheduler-3 · 进程调度","description":"","frontmatter":{"title":"020-proc-scheduler-3 · 进程调度"},"headers":[],"relativePath":"tutorial/020-proc-scheduler-3.md","filePath":"tutorial/020-proc-scheduler-3.md","lastUpdated":1779686691000}'),i={name:"tutorial/020-proc-scheduler-3.md"};function c(o,s,p,l,d,r){return a(),n("div",null,[...s[0]||(s[0]=[t(`<h1 id="抢占调度的两个暗坑" tabindex="-1">抢占调度的两个暗坑 <a class="header-anchor" href="#抢占调度的两个暗坑" aria-label="Permalink to &quot;抢占调度的两个暗坑&quot;">​</a></h1><blockquote><p>标签：调试, 时间片, IF 标志, context_switch, sti, 中断门 前置：<a href="./020-proc-scheduler-2">020-2 时间片轮转：从 tick 到 context_switch</a></p></blockquote><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>前两篇我们把抢占式调度器&quot;应该怎样工作&quot;讲清楚了——Spinlock 保护共享队列、PerCPU 保存运行时状态、tick 驱动时间片轮转、schedule 做上下文切换。现在该讲点真实的东西了：我实际上把这些代码跑起来的时候，到底发生了什么。</p><p>说实话，tag 020 的 debug 过程比 tag 019 还要&quot;精彩&quot;。tag 019 的三个 bug 各自独立，虽然诡异但因果关系比较清晰。tag 020 的两个暗坑则是一环扣一环：第一个坑让抢占根本没触发，我修好之后信心满满地加到 6 个线程准备看漂亮的轮转输出，结果撞上了第二个坑——只有第一个被抢占的任务能恢复中断，后续 5 个线程全部带着 IF=0 跑到结束。串口输出里的线程 A 切出去之后，B/C/D/E/F 就像商量好了似的排着队顺序跑完，仿佛调度器完全不存在。这一章我们就一个一个拆。</p><h2 id="暗坑-1-时间片过长-抢占从未触发" tabindex="-1">暗坑 1：时间片过长，抢占从未触发 <a class="header-anchor" href="#暗坑-1-时间片过长-抢占从未触发" aria-label="Permalink to &quot;暗坑 1：时间片过长，抢占从未触发&quot;">​</a></h2><p>说实话，这个坑让我怀疑了自己整整一个下午。代码逻辑看起来完全正确——PIT 以 100Hz 产生 IRQ0、ISR stub 调用 <code>PIT::irq0_handler()</code>、handler 递增 tick 后调用 <code>Scheduler::tick()</code>、tick 计数器达到阈值后调用 <code>schedule()</code>。每一步都对。但串口输出就是没有交错的迹象。让我们从头开始拆。</p><h3 id="现象" tabindex="-1">现象 <a class="header-anchor" href="#现象" aria-label="Permalink to &quot;现象&quot;">​</a></h3><p>先看第一个 bug。3 个线程各跑 5 次迭代，完全顺序执行，没有任何交错：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[A] thread_a iteration 0</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>[A] thread_a iteration 4</span></span>
<span class="line"><span>[B] thread_b iteration 0</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>[B] thread_b iteration 4</span></span>
<span class="line"><span>[C] thread_c iteration 0</span></span>
<span class="line"><span>...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>三个线程像排好队一样一个接一个跑完，完全没有抢占的迹象。看起来像是合作式调度——但代码里根本没有 <code>yield()</code> 调用。定时器中断明明在跑，<code>tick()</code> 也被调用了，为什么没有触发切换？</p><h3 id="根因" tabindex="-1">根因 <a class="header-anchor" href="#根因" aria-label="Permalink to &quot;根因&quot;">​</a></h3><p>问题出在一个非常朴素但容易被忽略的地方：时间片太长了。</p><p>PIT 配置为 100Hz（每 tick 10ms），<code>DEFAULT_TIME_SLICE</code> 最初设为 10，也就是说 100ms 才触发一次抢占。而忙循环 <code>for (volatile int j = 0; j &lt; 1000000; j++) {}</code> 在 QEMU TCG 模式下执行极快——单次迭代不到 5ms。每个线程 5 次迭代总耗时不到 50ms，远小于 100ms 的时间片。线程在自己的时间片内就跑完了，定时器中断根本没来得及介入。</p><p>这是一个在虚拟化环境中特别容易踩的坑。物理机上 100 万次空循环可能需要 50-100ms，但在 QEMU TCG 模式下——尤其是较新版本的 QEMU 对简单指令序列有优化——10-20ms 就跑完了。你以为时间片足够短，实际上工作负载更轻。</p><h3 id="修复" tabindex="-1">修复 <a class="header-anchor" href="#修复" aria-label="Permalink to &quot;修复&quot;">​</a></h3><p>修复方案是双管齐下。第一，缩短时间片：<code>DEFAULT_TIME_SLICE</code> 从 10 改为 2（20ms）。第二，增大忙循环：迭代次数从 100 万提升到 2000 万，确保每个线程至少需要 3-5 个时间片才能完成。</p><div class="language-cpp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// scheduler.hpp</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">static</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> constexpr</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> DEFAULT_TIME_SLICE </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // 原来是 10</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// main.cpp</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">volatile</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> j </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; j </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 20000000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; j</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">++</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {}</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // 原来是 1000000</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>这个参数组合（2 tick / 20ms 时间片 + 20M 次忙循环）在 QEMU TCG 和 KVM 模式下都能可靠地触发抢占。OSDev Wiki 的 Scheduling Algorithms 页面建议&quot;A frequently chosen compromise for the quantum is between 20ms and 50ms&quot;——20ms 正好在推荐范围的下限，对教学内核来说足够紧凑。</p><p>这个 bug 的调试过程本身值得一提。当三个线程顺序跑完时，我首先怀疑的是 <code>tick()</code> 根本没被调用——也许中断没开？也许 EOI 没发？于是在 <code>tick()</code> 入口加了一行 <code>kprintf</code>，重新运行后发现 <code>tick()</code> 确实在被调用，而且 <code>current_slice_</code> 在稳定增长。接下来怀疑 <code>schedule()</code> 有问题——也许 <code>pick_next()</code> 返回了 null？又加了一行打印，发现 <code>schedule()</code> 根本没被调用。问题缩小到 <code>if (current_slice_ &gt;= DEFAULT_TIME_SLICE)</code> 这个条件——<code>current_slice_</code> 增长到 9（即 10 个 tick 后），才触发了 <code>schedule()</code>。这时候才恍然大悟：10 个 tick = 100ms，线程 50ms 就跑完了，当然等不到抢占。</p><h3 id="教训" tabindex="-1">教训 <a class="header-anchor" href="#教训" aria-label="Permalink to &quot;教训&quot;">​</a></h3><p>在虚拟化环境中测试抢占调度时，要确保工作负载足够大或者时间片足够小，让定时器中断有机会介入。不要想当然地认为&quot;100 万次循环应该够了&quot;——在 TCG 模式下可能真的不够。一个更稳健的测试策略是故意把时间片设到最小（1 tick = 10ms），让抢占尽可能频繁地发生，这样更容易暴露调度器中的其他问题。同时注意，不要用 <code>kprintf</code> 作为工作负载来测试抢占——<code>kprintf</code> 涉及串口 I/O，执行时间不可预测，在不同环境下差异极大。用纯 CPU 计算的忙循环（<code>for (volatile int j = 0; j &lt; N; j++) {}</code>）加上 <code>volatile</code> 防止优化，是更可靠的测试手段。</p><h2 id="暗坑-2-context-switch-丢失-if-标志" tabindex="-1">暗坑 2：context_switch 丢失 IF 标志 <a class="header-anchor" href="#暗坑-2-context-switch-丢失-if-标志" aria-label="Permalink to &quot;暗坑 2：context_switch 丢失 IF 标志&quot;">​</a></h2><p>第一个 bug 修好后我以为应该没问题了——时间片缩短到 20ms，忙循环增加到 2000 万次，6 个线程轮转起来应该能看到漂亮的交替输出。信心满满地重新编译运行，结果看到了一个比第一个 bug 更诡异的现象。这个 bug 从发现问题到找到根因花了我整整一个晚上，因为它的表现形式非常有迷惑性——不是&quot;不工作&quot;，而是&quot;工作了一半&quot;。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[A] tid=2 iter 1/10</span></span>
<span class="line"><span>[A] tid=2 iter 2/10          &lt;- 第一次抢占发生在这里</span></span>
<span class="line"><span>[B] tid=3 iter 1/10</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>[B] tid=3 iter 10/10         &lt;- B 跑完，从未被抢占</span></span>
<span class="line"><span>[B] done</span></span>
<span class="line"><span>[C] tid=4 iter 1/10</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>[F] done</span></span>
<span class="line"><span>[A] tid=2 iter 3/10          &lt;- A 回来继续</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>[A] done</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>A 跑了 2 次迭代后被成功抢占，切到了 B。但 B 从头到尾跑完了 10 次迭代，中间没有任何抢占。C、D、E、F 也一样——全部顺序跑完。只有 A 在被抢占后，等到 B-F 都跑完了才回来继续执行。这个现象非常反直觉：如果抢占成功了第一次，为什么后续的抢占全部失败？调度器选了下一个任务并执行了 <code>context_switch</code>，但切换过去之后，新任务似乎再也收不到定时器中断了。</p><p>这个现象说明什么？第一次抢占成功了，但后续所有的抢占都失败了。调度器选了下一个任务并执行了 <code>context_switch</code>，但切换过去之后，新任务再也收不到定时器中断。定时器中断被&quot;吞&quot;了。</p><h3 id="根因-中断门、rflags-和-callee-saved-的盲区" tabindex="-1">根因：中断门、RFLAGS 和 callee-saved 的盲区 <a class="header-anchor" href="#根因-中断门、rflags-和-callee-saved-的盲区" aria-label="Permalink to &quot;根因：中断门、RFLAGS 和 callee-saved 的盲区&quot;">​</a></h3><p>这个 bug 的根因藏在 x86 中断处理的一个非常微妙的硬件细节里，而且和 tag 019 遗留的一个设计假设有关——<code>context_switch</code> 从来不需要关心 RFLAGS。这个假设在合作式调度中完全成立，但在抢占式调度中就失效了。事情要从抢占发生时的调用链说起：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>IRQ0 -&gt; ISR stub (CPU 清除 IF) -&gt; pit_irq0_handler -&gt; Scheduler::tick() -&gt; schedule() -&gt; context_switch</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Intel SDM Vol. 3A Section 6.12.1.3 明确指出：&quot;When accessing an exception- or interrupt-handling procedure through an interrupt gate, the processor clears the IF flag to prevent other interrupts from interfering with the current interrupt handler。&quot; 进入 ISR 的那一刻，CPU 自动把 RFLAGS 的 IF 位清零了。这是中断门的语义——不同于陷阱门（trap gate），中断门会在进入 handler 时自动关中断。</p><p>现在关键来了。<code>context_switch.S</code> 只保存和恢复 callee-saved 寄存器——r15、r14、r13、r12、rbp、rbx，加上 RSP 和 RIP。总共 8 个 64 位值，64 字节。RFLAGS 不在其中。这不是疏忽——在 tag 019 的合作式调度中，<code>context_switch</code> 总是从普通函数（<code>yield()</code>）中被调用的，IF 保持为 1，不存在 RFLAGS 被修改的问题。</p><p>但 tag 020 的 <code>context_switch</code> 现在可以从 ISR 上下文中被调用了。此时 IF=0。当它通过 <code>jmp *56(%rsi)</code> 跳转到新任务时，新任务继承了 IF=0 的状态。对于首次运行的新任务——<code>ctx.rip</code> 指向入口函数，<code>jmp</code> 直接跳转过去——IF 仍然是 0。这意味着该任务永远收不到定时器中断，永远不会被抢占。</p><p>那被抢占后恢复运行的老任务呢？它们的恢复路径是这样的：<code>context_switch</code> 的 <code>.restore</code> 标签恢复 callee-saved 寄存器，然后 <code>ret</code> 回到调用链的上层——<code>schedule()</code> -&gt; <code>tick()</code> -&gt; <code>pit_irq0_handler</code> -&gt; ISR stub -&gt; <code>IRETQ</code>。Intel SDM Vol. 3A Section 6.12.1 指出：&quot;The IRET instruction is similar to the RET instruction except that it restores the saved flags into the EFLAGS register。&quot; IRETQ 从栈上的中断帧还原原始 RFLAGS——其中 IF=1。所以老任务不受影响。</p><p>这完美地解释了串口输出：A 被抢占后，它的恢复路径经过 IRETQ 还原了 IF=1，所以 A 后来能继续被调度。但 B、C、D、E、F 是首次运行的新任务，<code>jmp *56(%rsi)</code> 直接跳到入口函数，跳过了 IRETQ 的 RFLAGS 恢复——IF 保持为 0，定时器中断永远到不了。</p><h3 id="修复-一行-sti" tabindex="-1">修复：一行 sti <a class="header-anchor" href="#修复-一行-sti" aria-label="Permalink to &quot;修复：一行 sti&quot;">​</a></h3><p>修复方法简单到让人想抽自己——在 <code>context_switch.S</code> 中，切换栈之后、跳转到新任务之前加一条 <code>sti</code>：</p><div class="language-asm vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    /* Switch to the new task&#39;s stack */</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    movq</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 48</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(%</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rsi</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">), %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rsp</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # to+48-&gt;%rsp: switch stack pointer</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    /* Re-enable interrupts -- we may have entered from ISR context (IF=0).</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       New tasks must start with interrupts on; resumed tasks will restore</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       their original RFLAGS via IRETQ unwinding regardless. */</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    sti</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    /* Jump to the new task&#39;s saved instruction pointer */</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    jmp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> *</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">56</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(%</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rsi</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)                   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # to+56-&gt;RIP: resume execution</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>为什么这条 <code>sti</code> 是安全的？分两种情况看。对于新任务，<code>sti</code> 正确地把 IF 设为 1，定时器中断正常到达，抢占正常工作。对于被抢占后恢复的老任务，恢复路径最终经过 IRETQ 会还原原始 RFLAGS——如果原来 IF=1，IRETQ 恢复 IF=1，<code>sti</code> 的效果被覆盖；如果原来 IF=0（理论上不应该，但假设有这种场景），IRETQ 也会恢复 IF=0。所以 <code>sti</code> 对老任务是无害的冗余操作。</p><p>有人可能会担心嵌套中断的风险——从 <code>sti</code> 到 IRETQ 的退栈路径中，中断已经打开，如果此时又一个定时器中断到达怎么办？实际上这个窗口极短——微秒级，而定时器间隔是 10ms——命中的概率可以忽略。即使真的命中了，也不会出问题：第二次 <code>tick()</code> 会看到当前任务的时间片还没耗尽（刚刚重置过），直接返回。</p><h3 id="sti-为什么放在-context-switch-而不是-isr-stub-里" tabindex="-1">sti 为什么放在 context_switch 而不是 ISR stub 里？ <a class="header-anchor" href="#sti-为什么放在-context-switch-而不是-isr-stub-里" aria-label="Permalink to &quot;sti 为什么放在 context_switch 而不是 ISR stub 里？&quot;">​</a></h3><p>一种替代方案是在 ISR stub 中、调用 <code>context_switch</code> 之后再 <code>sti</code>——如果发生了切换的话。但这需要 ISR stub 知道是否发生了切换，增加了 ISR 和调度器之间的耦合。而且 ISR stub 要怎么知道&quot;是否发生了切换&quot;？要么让 <code>context_switch</code> 返回一个 bool（改变了函数签名），要么引入一个全局标志（引入了额外的共享状态）。这两种方案都不如把 <code>sti</code> 放在 <code>context_switch</code> 内部来得干净。</p><p>把 <code>sti</code> 放在 <code>context_switch</code> 内部，紧挨着栈切换之后，是语义最清晰的位置：&quot;我已经在新任务的栈上了，该让中断恢复工作了。&quot;这种自包含的设计让 <code>context_switch</code> 在任何上下文（ISR、普通函数）中调用都能正确工作，调用者不需要知道 <code>context_switch</code> 内部是否有 <code>sti</code>——它只关心&quot;切换完成后新任务的中断状态是正确的&quot;。</p><h3 id="一种更精细但没必要的方案" tabindex="-1">一种更精细但没必要的方案 <a class="header-anchor" href="#一种更精细但没必要的方案" aria-label="Permalink to &quot;一种更精细但没必要的方案&quot;">​</a></h3><p>另一种修复思路是把 RFLAGS 加入 <code>CpuContext</code> 结构体，在保存 callee-saved 时用 <code>pushfq</code> 保存 RFLAGS，恢复时用 <code>popfq</code> 还原。这种方案更&quot;完整&quot;——它不仅解决了 IF 问题，还能正确处理其他标志位（比如 DF、AF 等）。但对当前仅内核线程的场景来说，这些标志位的状态不是问题——内核代码不会假设某个标志位的初始值。而且多保存/恢复一个 RFLAGS（8 字节 + 两条指令）会增加 <code>context_switch</code> 的开销和 <code>CpuContext</code> 的大小——从 64 字节变成 72 字节，汇编代码中的所有偏移量都要调整。对教学内核来说，一条 <code>sti</code> 是最简洁的修复。</p><p>如果未来引入用户态任务，需要在 <code>context_switch</code> 中保存和恢复完整的状态（包括 FPU、MXCSR、debug 寄存器等），那时再考虑把 RFLAGS 加入 <code>CpuContext</code> 也不迟。当前的方案遵循&quot;够用就好&quot;的原则。</p><p>实际上，<code>CpuContext</code> 结构体从 tag 019 到现在只有 8 个字段、64 字节。保持这个结构体的精简是刻意的——每多加一个字段，汇编代码中的偏移量就要全部调整，<code>static_assert</code> 也要更新。在确认需要之前不加字段，是避免过早复杂化的好习惯。</p><p>这个 bug 的调试比第一个更有挑战性。看到串口输出时，我最初的直觉是&quot;定时器中断停了&quot;——B/C/D/E/F 全部跑完没被抢占，说明中断确实没到。但 A 被抢占过，说明中断机制本身是工作的。接下来怀疑是不是 <code>context_switch</code> 之后中断被关了——于是在 <code>context_switch</code> 返回后立即检查 RFLAGS 的 IF 位，果然是 0。顺着调用链回溯：IRQ0 进入时 CPU 自动清 IF（中断门语义），<code>tick()</code> -&gt; <code>schedule()</code> -&gt; <code>context_switch</code> 全程 IF=0，<code>context_switch</code> 的 <code>jmp *56(%rsi)</code> 把 IF=0 的状态带到了新任务。而新任务没有 IRETQ 的退栈路径来恢复 IF——它直接从入口函数开始执行。问题就在这里。</p><p>排查这个 bug 的关键一步是在纸上画出&quot;新任务&quot;和&quot;被抢占后恢复的老任务&quot;两条不同的恢复路径。新任务走的是 <code>jmp -&gt; entry function</code>，不经过 IRETQ；老任务走的是 <code>.restore -&gt; ret -&gt; schedule() -&gt; tick() -&gt; ISR stub -&gt; IRETQ</code>。两条路径对 RFLAGS 的处理完全不同——新任务继承了当前的 IF=0，老任务通过 IRETQ 恢复了原始的 IF=1。一旦画清楚这两条路径，修复方案就显而易见了：在新任务的路径上补一个 <code>sti</code>。这种&quot;在纸上画执行路径&quot;的方法对于涉及寄存器状态和栈指针的 bug 几乎是唯一可靠的方法——对着代码读很难发现&quot;这条路径没恢复 IF&quot;，但画出来就一目了然了。</p><p>值得一提的是，这个 bug 和 tag 019 的 <code>0xDEADC0DE</code> bug 有着相似的&quot;气味&quot;——都是因为 <code>context_switch</code> 用 <code>jmp</code> 而不是 <code>call</code> 跳到新任务，导致某些&quot;隐式传递&quot;的状态出了问题。tag 019 的问题是栈上没有返回地址（<code>jmp</code> 不压返回地址），tag 020 的问题是 IF 被清零（<code>jmp</code> 不恢复 RFLAGS）。两次都是同一个根因的不同表现：<code>jmp</code> 指令不做任何&quot;附带操作&quot;，它只改 RIP。如果调用者依赖了某些&quot;附带状态&quot;（栈上的返回地址、RFLAGS 中的 IF），就必须自己保证这些状态在新任务上是正确的。</p><h2 id="全部修完后的串口输出" tabindex="-1">全部修完后的串口输出 <a class="header-anchor" href="#全部修完后的串口输出" aria-label="Permalink to &quot;全部修完后的串口输出&quot;">​</a></h2><p>两个 bug 全部修完后，6 个线程终于实现了真正的抢占式轮转：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[BIG] Starting preemptive demo (6 threads x 10 iters, timer-driven)...</span></span>
<span class="line"><span>[A] tid=2 iter 1/10</span></span>
<span class="line"><span>[A] tid=2 iter 2/10</span></span>
<span class="line"><span>[B] tid=3 iter 1/10</span></span>
<span class="line"><span>[B] tid=3 iter 2/10</span></span>
<span class="line"><span>[C] tid=4 iter 1/10</span></span>
<span class="line"><span>[C] tid=4 iter 2/10</span></span>
<span class="line"><span>[D] tid=5 iter 1/10</span></span>
<span class="line"><span>[D] tid=5 iter 2/10</span></span>
<span class="line"><span>[E] tid=6 iter 1/10</span></span>
<span class="line"><span>[E] tid=6 iter 2/10</span></span>
<span class="line"><span>[F] tid=7 iter 1/10</span></span>
<span class="line"><span>[F] tid=7 iter 2/10</span></span>
<span class="line"><span>[A] tid=2 iter 3/10</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>[F] done</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br></div></div><p>每个线程跑 2 次迭代后被抢占（20ms 时间片），然后下一个线程接手。6 个线程轮转执行，没有任何 <code>yield()</code> 调用。看着这串输出，你就能感受到&quot;抢占式调度&quot;和&quot;合作式调度&quot;之间的根本区别——线程不需要配合，调度器也不需要信任线程。定时器中断是公平的裁判，每 20ms 吹一次哨，该换人了。</p><h2 id="回头看-从合作式到抢占式的隐藏代价" tabindex="-1">回头看：从合作式到抢占式的隐藏代价 <a class="header-anchor" href="#回头看-从合作式到抢占式的隐藏代价" aria-label="Permalink to &quot;回头看：从合作式到抢占式的隐藏代价&quot;">​</a></h2><p>这两个 bug 放在一起看，其实反映的是同一个深层问题：合作式调度和抢占式调度之间的鸿沟比表面上大得多。表面上看，tag 020 只是在 <code>tick()</code> 里加了几行代码、把 <code>yield()</code> 改成了由定时器驱动——&quot;不就是换了个触发方式嘛&quot;。但实际上，从中断驱动的调度开始生效的那一刻起，你的 <code>context_switch</code> 就不再只是从一个普通函数中被调用了——它可能从中断上下文中被调用，而中断上下文有着完全不同的 RFLAGS 状态。这个&quot;调用上下文的改变&quot;引入了新的正确性约束，而旧的代码（<code>context_switch.S</code>）是在没有这些约束的情况下设计的。</p><p>这也是为什么 Linux 的 <code>switch_to</code> 宏做得那么&quot;重&quot;——它不仅要保存 callee-saved 寄存器，还要处理 FPU 状态、debug 寄存器、IO 位图、thread-local storage 等等。每一个&quot;附带状态&quot;都是在一个特定的调用场景中被发现的 bug 的修复结果。Cinux 的 <code>context_switch</code> 目前只需要处理 callee-saved 和 IF 标志，但这只是起点。</p><h2 id="回头看-这两个暗坑教会了我们什么" tabindex="-1">回头看：这两个暗坑教会了我们什么 <a class="header-anchor" href="#回头看-这两个暗坑教会了我们什么" aria-label="Permalink to &quot;回头看：这两个暗坑教会了我们什么&quot;">​</a></h2><p>这两个 bug 有一个共同特点：它们都不是&quot;编译报错&quot;或&quot;立刻 crash&quot;那种明显的错误。第一个 bug 让系统正常运行——线程跑完了该跑的逻辑，只是没有交替。如果你不仔细看输出，甚至可能觉得&quot;线程跑完再切换不也挺正常吗&quot;。第二个 bug 更隐蔽——只有第一个被抢占的任务受影响，后续线程都&quot;正常&quot;跑完了（只不过是从头到尾跑完，中间没有抢占）。两个 bug 的表现形式都像是&quot;正常行为&quot;，只有当你知道&quot;应该是怎样&quot;时才能看出不对。</p><p>内核调试的经验之一就是：在涉及中断和上下文切换的代码中，你看到的往往是间接现象而不是根因。&quot;线程顺序跑完&quot;不是调度器没调用 <code>schedule()</code>，而是时间片设置和工作负载不匹配；&quot;后续线程没被抢占&quot;不是定时器停了，而是 <code>context_switch</code> 没有正确传递中断状态。找到根因的关键是回到硬件的执行模型——每条指令执行后，CPU 的状态是什么，RFLAGS 的每一位是什么，中断是否可达。</p><p>另一个教训是关于从合作式到抢占式的迁移。合作式 context_switch 的设计不需要考虑 RFLAGS——总是在明确的调用点切换，IF 不变。但一旦从中断上下文调用同一个 <code>context_switch</code>，就必须保证新任务的中断状态正确。这是从 cooperative 迈向 preemptive 的经典陷阱——你的 <code>context_switch</code> 函数签名没变、实现逻辑没变，但调用上下文变了，隐藏的前提假设就被打破了。Linux 在 <code>switch_to</code> 中不需要担心这个问题，因为它在调度点有完善的 RFLAGS 管理；xv6 的 <code>swtch</code> 也不需要担心，因为它总是从 <code>sched()</code> 调用，而 <code>sched()</code> 运行在中断开启的 scheduler 上下文中。Cinux 的特殊情况在于 <code>context_switch</code> 第一次被从中断上下文中调用——而这个调用上下文引入了 IF=0 的隐含约束。</p><p>最后一个教训和测试有关。这两个 bug 说明了一件事：抢占式调度不能只靠&quot;代码审查看起来对&quot;来验证。你必须设计出真正能暴露问题的测试负载。第一个 bug 的教训是：测试抢占时，工作负载必须跨越多个时间片。第二个 bug 的教训是：测试线程数不能太少——只有两个线程时，第一个被抢占的线程（A）通过 IRETQ 恢复了 IF=1 然后回来继续跑，你看到的输出&quot;看起来是交替的&quot;，但实际上 B 在自己的时间片里带着 IF=0 跑完了。加到 6 个线程后 B-F 全部带着 IF=0 跑完，问题才变得明显。</p><h2 id="收尾" tabindex="-1">收尾 <a class="header-anchor" href="#收尾" aria-label="Permalink to &quot;收尾&quot;">​</a></h2><p>tag 020 到这里就完整了。我们从 Spinlock、PerCPU、TSS.RSP0 三块基础设施开始，搭建了抢占式调度所需的安全框架。然后实现了 tick 驱动的时间片轮转、idle 任务的兜底机制、block/unblock 为同步原语的铺路。最后在调试中踩了两个经典的暗坑——时间片过长导致抢占从未触发、context_switch 丢失 IF 标志导致后续线程中断全关——并且逐个拆解了它们的根因和修复方案。</p><p>521 行新增代码，127 行删除，19 个文件变更。从&quot;线程必须 yield 才能切换&quot;到&quot;定时器中断强制切换&quot;，这是 Cinux 调度系统的质变。回头看，tag 020 最重要的教训不是具体的代码实现，而是一个设计理念：当你的代码从一种调用上下文（普通函数）迁移到另一种调用上下文（中断处理）时，必须重新审视所有隐含的前提假设。<code>context_switch</code> 在 tag 019 中从不关心 RFLAGS——因为 <code>yield()</code> 在普通上下文中被调用，IF 始终为 1。但当中断驱动的 <code>tick()</code> -&gt; <code>schedule()</code> -&gt; <code>context_switch</code> 链路建立起来后，IF=0 成了新的常态，而旧代码对此一无所知。这种&quot;调用上下文的改变引入了新的正确性约束&quot;的模式在内核开发中反复出现，值得牢记。</p><p>下一个 tag 是 <code>021_proc_sync</code>——在抢占式调度的基础上实现 Mutex 和 Semaphore，用 block/unblock 机制让线程在锁竞争时真正地等待和唤醒。到时候抢占式调度就不再只是&quot;定时器打断线程&quot;这么简单了——它会成为内核同步原语的基石。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li>Intel SDM Vol. 3A, Section 2.3 &quot;System Flags and Fields in the EFLAGS Register&quot; (PDF pages 71-73)：IF 标志控制可屏蔽中断</li><li>Intel SDM Vol. 3A, Section 6.12.1.3 &quot;Flag Usage By Exception- or Interrupt-Handler Procedure&quot; (PDF page 213)：中断门自动清除 IF——本 bug 的直接根因</li><li>Intel SDM Vol. 3A, Section 6.8.1 &quot;Masking Maskable Hardware Interrupts&quot; (PDF page 203)：IF=0 时 CPU 抑制 INTR 引脚的中断请求</li><li>Intel SDM Vol. 3A, Section 6.12.1 &quot;Procedure Calls and Returns for Exception- and Interrupt-Handling&quot; (PDF page 209)：IRETQ 恢复 RFLAGS——老任务不受影响的原因</li><li>OSDev Wiki, &quot;Scheduling Algorithms&quot;：<a href="https://wiki.osdev.org/Scheduling_Algorithms" target="_blank" rel="noreferrer">https://wiki.osdev.org/Scheduling_Algorithms</a> — 时间片建议 20ms-50ms</li><li>document/notes/020/001_time_slice_too_long.md：时间片过长问题的完整调试记录</li><li>document/notes/020/002_if_flag_lost_in_context_switch.md：IF 标志丢失的完整调试记录</li></ul>`,68)])])}const b=e(i,[["render",c]]);export{u as __pageData,b as default};
